import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Validate inputs
        if not filename or not dir_path:
            return ""

        # Prevent path traversal attacks
        if ".." in filename or "/" in filename or "\\" in filename:
            return ""

        # Construct full path
        full_path = os.path.join(dir_path, filename)

        # Ensure the path is within the given directory
        if not os.path.abspath(full_path).startswith(os.path.abspath(dir_path)):
            return ""

        # Read file content
        with open(full_path, 'r', encoding='utf-8') as file:
            return file.read()

    except (IOError, OSError, UnicodeDecodeError, ValueError):
        return ""

import ast
import operator

def evaluate_expression(expr: str) -> str:
    try:
        # Parse the expression
        node = ast.parse(expr, mode='eval')

        # Define allowed operators
        operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def evaluate(node):
            if isinstance(node, ast.Expression):
                return evaluate(node.body)
            elif isinstance(node, ast.Num):  # For Python < 3.8
                return node.n
            elif isinstance(node, ast.Constant):  # For Python >= 3.8
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Only numbers are allowed")
            elif isinstance(node, ast.BinOp):
                left = evaluate(node.left)
                right = evaluate(node.right)
                op_type = type(node.op)
                if op_type in operators:
                    return operators[op_type](left, right)
                else:
                    raise ValueError(f"Operator {op_type} not allowed")
            elif isinstance(node, ast.UnaryOp):
                operand = evaluate(node.operand)
                op_type = type(node.op)
                if op_type in operators:
                    return operators[op_type](operand)
                else:
                    raise ValueError(f"Unary operator {op_type} not allowed")
            elif isinstance(node, ast.Call):
                raise ValueError("Function calls are not allowed")
            elif isinstance(node, ast.Name):
                raise ValueError("Variables are not allowed")
            elif isinstance(node, ast.Attribute):
                raise ValueError("Attribute access is not allowed")
            else:
                raise ValueError(f"Expression type {type(node)} not allowed")

        result = evaluate(node)
        return str(result)
    except Exception:
        return ""

import jwt
from typing import Dict


def decode_json_web_token(token: str, key: str) -> Dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    if not token or not key:
        return {}

    try:
        # Decode with verification enabled
        payload = jwt.decode(
            token,
            key,
            algorithms=['HS256'],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
            }
        )
        return payload if isinstance(payload, dict) else {}
    except (jwt.InvalidTokenError, jwt.DecodeError, jwt.InvalidSignatureError,
            jwt.ExpiredSignatureError, jwt.InvalidAudienceError,
            jwt.InvalidIssuerError, jwt.InvalidKeyError,
            jwt.ImmatureSignatureError, jwt.MissingRequiredClaimError):
        return {}

import re
import signal
from contextlib import contextmanager

class TimeoutError(Exception):
    pass

@contextmanager
def timeout_context(seconds):
    def signal_handler(signum, frame):
        raise TimeoutError("Operation timed out")

    old_handler = signal.signal(signal.SIGALRM, signal_handler)
    signal.alarm(seconds)
    try:
        yield
    finally:
        signal.alarm(0)
        signal.signal(signal.SIGALRM, old_handler)

def search_pattern(pattern: str, content: str) -> bool:
    try:
        # Validate inputs
        if not isinstance(pattern, str) or not isinstance(content, str):
            return False

        # Limit pattern length to prevent overly complex patterns
        if len(pattern) > 1000:
            return False

        # Limit content length to prevent processing huge inputs
        if len(content) > 1000000:
            return False

        # Compile the pattern with timeout to prevent ReDoS
        try:
            with timeout_context(5):  # 5 second timeout
                compiled_pattern = re.compile(pattern, re.IGNORECASE)
        except (re.error, TimeoutError):
            return False

        # Search with timeout
        try:
            with timeout_context(5):  # 5 second timeout
                match = compiled_pattern.search(content)
                return match is not None
        except TimeoutError:
            return False

    except Exception:
        # Catch any other unexpected errors
        return False

from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    """
    Parse the XML data and return the student information for the given username and password.
    """
    try:
        # Create a secure parser to prevent XXE attacks
        parser = etree.XMLParser(no_network=True, resolve_entities=False)
        root = etree.fromstring(xml_data.encode('utf-8'), parser=parser)
    except (etree.XMLSyntaxError, etree.ParseError):
        return None

    # Use parameterized XPath to prevent injection
    xpath_expr = "/students/student[username=$username and password=$password]"
    students = root.xpath(xpath_expr, username=username, password=password)

    if not students:
        return None

    student = students[0]
    try:
        name = student.findtext("name", default="")
        citizenship = student.findtext("citizenship", default="")
        age = student.findtext("age", default="")

        if not all([name, citizenship, age]):
            return None

        return {
            "name": name,
            "citizenship": citizenship,
            "age": age,
        }
    except (AttributeError, IndexError):
        return None

