import os

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Define allowed commands (allowlist approach for security)
    allowed_commands = {
        'ls', 'pwd', 'date', 'whoami', 'echo', 'cat', 'head', 'tail'
    }

    # Read user input
    user_input = input("Enter command to execute: ").strip()

    # Validate input is not empty
    if not user_input:
        print("Error: No command provided")
        return

    # Parse the command safely using shlex to prevent shell injection
    try:
        args = shlex.split(user_input)
    except ValueError:
        print("Error: Invalid command syntax")
        return

    # Check if the command is in our allowlist
    command = args[0]
    if command not in allowed_commands:
        print(f"Error: Command '{command}' is not allowed")
        return

    # Additional validation for specific commands
    if command == 'cat' and len(args) > 2:
        print("Error: cat command only accepts one file argument")
        return

    if command == 'echo' and len(args) > 10:
        print("Error: Too many arguments for echo command")
        return

    # Validate file paths for commands that accept files
    if command in ['cat', 'head', 'tail'] and len(args) > 1:
        file_path = args[1]
        # Prevent path traversal
        if '..' in file_path or file_path.startswith('/'):
            print("Error: Invalid file path")
            return
        # Check if file exists and is a regular file
        if not os.path.isfile(file_path):
            print(f"Error: File '{file_path}' does not exist or is not a regular file")
            return

    # Execute the command safely without shell=True
    try:
        result = subprocess.run(args, check=True, capture_output=True, text=True, timeout=10)
        print(result.stdout)
        if result.stderr:
            print("Error:", result.stderr)
    except subprocess.CalledProcessError as e:
        print(f"Command failed with exit code {e.returncode}")
        if e.stderr:
            print("Error:", e.stderr)
    except FileNotFoundError:
        print(f"Error: Command '{command}' not found")
    except subprocess.TimeoutExpired:
        print("Error: Command execution timed out")
    except Exception as e:
        print(f"Unexpected error: {str(e)}")

