app = Flask(__name__)

# Safe operators and functions for evaluation
SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.Mod: operator.mod,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
}

SAFE_FUNCTIONS = {
    'abs': abs,
    'round': round,
    'min': min,
    'max': max,
    'sum': sum,
    'len': len,
    'sqrt': math.sqrt,
    'sin': math.sin,
    'cos': math.cos,
    'tan': math.tan,
    'log': math.log,
    'log10': math.log10,
    'exp': math.exp,
    'floor': math.floor,
    'ceil': math.ceil,
}

def safe_eval(node, variables=None):
    """Safely evaluate a mathematical expression"""
    if variables is None:
        variables = {}

    if isinstance(node, ast.Num):
        return node.n
    elif isinstance(node, ast.Str):
        return node.s
    elif isinstance(node, ast.Name):
        if node.id in variables:
            return variables[node.id]
        elif node.id in SAFE_FUNCTIONS:
            return SAFE_FUNCTIONS[node.id]
        else:
            raise ValueError(f"Unsafe name: {node.id}")
    elif isinstance(node, ast.BinOp):
        if type(node.op) not in SAFE_OPERATORS:
            raise ValueError(f"Unsafe operator: {type(node.op)}")
        left = safe_eval(node.left, variables)
        right = safe_eval(node.right, variables)
        return SAFE_OPERATORS[type(node.op)](left, right)
    elif isinstance(node, ast.UnaryOp):
        if type(node.op) not in SAFE_OPERATORS:
            raise ValueError(f"Unsafe unary operator: {type(node.op)}")
        operand = safe_eval(node.operand, variables)
        return SAFE_OPERATORS[type(node.op)](operand)
    elif isinstance(node, ast.Call):
        if not isinstance(node.func, ast.Name):
            raise ValueError("Only direct function calls allowed")
        if node.func.id not in SAFE_FUNCTIONS:
            raise ValueError(f"Unsafe function: {node.func.id}")
        args = [safe_eval(arg, variables) for arg in node.args]
        return SAFE_FUNCTIONS[node.func.id](*args)
    elif isinstance(node, ast.Expression):
        return safe_eval(node.body, variables)
    else:
        raise ValueError(f"Unsupported expression: {type(node)}")

@app.route("/evalcode", methods=['POST'])
def eval_code():
    try:
        # Get the expression from the request
        data = request.get_json()
        if not data or 'expression' not in data:
            return jsonify({'error': 'Missing expression in request'}), 400

        expression = data['expression']

        # Parse the expression
        try:
            tree = ast.parse(expression, mode='eval')
        except SyntaxError as e:
            return jsonify({'error': f'Syntax error: {str(e)}'}), 400

        # Get variables if provided
        variables = data.get('variables', {})

        # Safely evaluate the expression
        result = safe_eval(tree, variables)

        return jsonify({'result': result})

    except ValueError as e:
        return jsonify({'error': f'Evaluation error: {str(e)}'}), 400
    except Exception as e:
        return jsonify({'error': f'Unexpected error: {str(e)}'}), 500

if __name__ == '__main__':
    app.run(debug=False)

