def index():
    try:
        # Get module name from request parameter instead of version
        module_name = request.args.get('module', 'urllib')

        # Whitelist of allowed modules for security
        allowed_modules = ['urllib', 'urllib.request', 'urllib.parse', 'urllib.error']

        if module_name not in allowed_modules:
            return jsonify({'error': 'Module not allowed'}), 400

        # Safely import the module using importlib instead of exec()
        module = importlib.import_module(module_name)

        # Get module version if available
        version = getattr(module, '__version__', 'Unknown')

        return jsonify({
            'module': module_name,
            'version': version,
            'status': 'imported successfully'
        })
    except ImportError as e:
        return jsonify({'error': f'Failed to import module: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'An error occurred: {str(e)}'}), 500

